const slaMeta=t=>{const d=t?.sla_deadline?new Date(t.sla_deadline).getTime():0;if(!d)return{cls:"",txt:"Sin SLA"};const left=d-Date.now(),h=Math.max(0,Math.round(left/36e5));if(left<=0)return{cls:"bad",txt:"Vencido"};if(left<=2*36e5)return{cls:"warn",txt:`${h}h restantes`};return{cls:"ok",txt:`${h}h restantes`}};
const detectSystemKey=t=>{const x=norm(`${t?.sistema||""} ${t?.sistema_detectado||""} ${t?.tipo_sistema||""} ${t?.categoria||""} ${t?.tipo||""} ${t?.titulo||""} ${t?.descripcion||""}`);if(x.includes("contabilidad")||x.includes("contabiliza")||x.includes("contab"))return"CONTABILIDAD";if(x.includes("bancos"))return"BANCOS";if(x.includes("nominas")||x.includes("nóminas")||x.includes("nomina"))return"NOMINAS";if(x.includes("xml en linea")||x.includes("xml"))return"XML_EN_LINEA";if(x.includes("comercial premium"))return"COMERCIAL_PREMIUM";if(x.includes("comercial pro"))return"COMERCIAL_PRO";if(x.includes("comercial start"))return"COMERCIAL_START";if(x.includes("factura electronica")||x.includes("factura"))return"FACTURA_ELECTRONICA";if(x.includes("evalua"))return"EVALUA";if(x.includes("analiza"))return"ANALIZA";if(x.includes("vende"))return"VENDE";if(x.includes("optimiza"))return"OPTIMIZA";if(x.includes("anticipa"))return"ANTICIPA";if(x.includes("personia"))return"PERSONIA";return""};
const systemLogoHtml=t=>{const k=detectSystemKey(t),src=SYS_LOGO[k]||"",label=t?.sistema||t?.sistema_detectado||t?.tipo_sistema||k||"—";return src?`<span class="tk-system-chip"><img src="${src}" alt="${esc(label)}" class="tk-system-logo"><span>${esc(label)}</span></span>`:`<span>${esc(label)}</span>`};
const smartWhen=v=>{if(!v)return"—";const d=new Date(v),now=new Date(),today=new Date(now.getFullYear(),now.getMonth(),now.getDate()),that=new Date(d.getFullYear(),d.getMonth(),d.getDate()),diff=Math.round((today-that)/86400000),hm=d.toLocaleTimeString("es-MX",{hour:"numeric",minute:"2-digit"});if(diff===0)return`Hoy · ${hm}`;if(diff===1)return`Ayer · ${hm}`;if(diff===2)return`Antier · ${hm}`;if(diff<=6)return`Hace ${diff} días · ${hm}`;return`${d.toLocaleDateString("es-MX",{day:"numeric",month:"long"})} · ${hm}`};
const humanAgo=v=>{if(!v)return"—";const d=new Date(v),now=new Date(),today=new Date(now.getFullYear(),now.getMonth(),now.getDate()),that=new Date(d.getFullYear(),d.getMonth(),d.getDate()),diff=Math.round((today-that)/86400000),hm=d.toLocaleTimeString("es-MX",{hour:"numeric",minute:"2-digit"});if(diff===0)return`Hoy · ${hm}`;if(diff===1)return`Ayer · ${hm}`;if(diff===2)return`Antier · ${hm}`;if(diff<=6)return`Hace ${diff} días · ${hm}`;return`${d.toLocaleDateString("es-MX",{day:"2-digit",month:"2-digit"})} · ${hm}`};

