const renderLogs=()=>{const author=T?.nombre_capturado||T?.nombre_cliente_contacto||C?.nombre||T?.empresa_capturada||"Cliente";$("#tkThreadStamp")&&($("#tkThreadStamp").textContent=`Recibido · ${humanAgo(T?.fecha_creacion)}`);const head=`<div class="log-msg"><div class="log-meta"><span>${esc(author)}</span><span>${fmtHM(T?.fecha_creacion)}</span></div>${esc(T?.descripcion||"Sin descripción")}</div>`;const tail=(LOGS||[]).map(humanLog).filter(Boolean).map(x=>`<div class="log-msg ${x.side==="me"?"me":""}"><div class="log-meta"><span>${esc(x.title)}</span><span>${esc(x.time)}</span></div>${esc(x.text)}</div>`).join("");$("#logArea").innerHTML=head+tail};
